/// 学習時と同じ正規化 + Linear(23→16) → ReLU → Linear(16→1) のforward pass。
/// 出力はlogit（Sigmoidではない）。呼び出し側は `exp(logit)` として使う
pub fn opp_move_nn_forward(features: &[f64; 23]) -> f64 {
    let mut x = [0.0f64; 23];
    for i in 0..23 {
        x[i] = (features[i] - OPP_MOVE_NN_MEAN[i]) / OPP_MOVE_NN_STD[i];
    }
    let mut h = [0.0f64; 16];
    for j in 0..16 {
        let mut s = OPP_MOVE_NN_B1[j];
        for i in 0..23 {
            s += OPP_MOVE_NN_W1[j][i] * x[i];
        }
        h[j] = s.max(0.0); // ReLU
    }
    let mut out = OPP_MOVE_NN_B2;
    for j in 0..16 {
        out += OPP_MOVE_NN_W2[j] * h[j];
    }
    out
}

#[cfg(test)]
mod tests {
    use super::*;

    /// プレースホルダ（ゼロ重み = 全候補一様）のまま誤ってマージ・凍結する
    /// 事故のガード（codexレビュー指摘、2026-07-22）
    #[test]
    fn weights_are_not_placeholder_zeros() {
        assert!(
            OPP_MOVE_NN_W1.iter().flatten().any(|&w| w != 0.0),
            "W1が全ゼロ = export_opp_move_weights.py 未実行のプレースホルダ"
        );
        assert!(OPP_MOVE_NN_W2.iter().any(|&w| w != 0.0));
    }

    /// numpy側で同じ定数（このファイルのAUTO-GENERATED区間）を独立に読み直して
    /// 計算した値との突き合わせ（行列の転置・インデックス取り違えの検出用）。
    /// 期待値の再生成はscratchpadのcrosscheck.py相当（Rustソースから定数を
    /// パースしてforwardをnumpyで再計算）で行う
    #[test]
    fn matches_numpy_cross_check() {
        let mut pawn_push = [0.0f64; 23];
        pawn_push[0] = 1.0; // advance
        pawn_push[13] = 1.0; // moved_pawn
        pawn_push[21] = 1.0; // move_dist
        pawn_push[22] = 1.0; // from_home
        let mut bishop_probe = [0.0f64; 23];
        bishop_probe[0] = 3.0; // advance
        bishop_probe[4] = 1.0; // threat_known
        bishop_probe[12] = 2.0; // opp_foul_count_this_turn
        bishop_probe[18] = 1.0; // moved_bishop
        bishop_probe[21] = 6.0; // move_dist
        bishop_probe[22] = 1.0; // from_home
        let cases: [([f64; 23], f64); 3] = [
            ([0.0; 23], 0.40666380289708765),
            (pawn_push, 0.23739242535023505),
            (bishop_probe, 1.1769182204989246),
        ];
        for (features, expected) in cases {
            let got = opp_move_nn_forward(&features);
            assert!(
                (got - expected).abs() < 1e-9,
                "features={features:?} got={got} expected={expected}"
            );
        }
    }

    /// opp_move_weight は1手の意思決定あたり最大10万回超のオーダーで
    /// 呼ばれる（粒子再生成時はさらに増える）。ONNX等の推論クレートを
    /// 避けて手書きforward passにした前提が崩れていないかのガード
    /// （数百FLOPのはずが将来誤って重くなったら検出する）
    #[test]
    fn forward_pass_is_fast_enough_for_hot_loop() {
        let mut features = [0.0f64; 23];
        features[0] = 1.0;
        features[4] = 1.0;
        features[9] = 1.0;
        let n = 1_000_000;
        let start = std::time::Instant::now();
        let mut acc = 0.0f64;
        for _ in 0..n {
            acc += opp_move_nn_forward(&std::hint::black_box(features));
        }
        let elapsed = start.elapsed();
        std::hint::black_box(acc);
        eprintln!("{n}回のforward pass: {elapsed:?}（1回あたり{:?}）", elapsed / n);
        // 実測は数十ns/回のオーダー（13次元時代で約48ns、23次元でも100ns未満）。
        // CI環境のノイズでflakyにならないよう10us/回まで大きく余裕を見た閾値
        assert!(
            elapsed.as_secs_f64() / f64::from(n) < 1e-5,
            "forward passが遅すぎる: {elapsed:?} / {n}回"
        );
    }
}
